### TextField

`TextField` is the primary widget for text input in Flutter.

```dart
TextField(
  controller: _controller,
  decoration: InputDecoration(
    labelText: 'Username',
    hintText: 'Enter your username',
    prefixIcon: const Icon(Icons.person),
    border: OutlineInputBorder(
      borderRadius: BorderRadius.circular(8),
    ),
  ),
  onChanged: (value) => print(value),
  onSubmitted: (value) => print('Submitted: $value'),
)
```

### TextEditingController

Always use a controller to manage text input state:

```dart
class _MyFormState extends State<MyForm> {
  final _nameController = TextEditingController();
  final _emailController = TextEditingController();
  final _formKey = GlobalKey<FormState>();

  @override
  void initState() {
    super.initState();
    _nameController.addListener(() {
      print('Name: ${_nameController.text}');
    });
  }

  @override
  void dispose() {
    _nameController.dispose();
    _emailController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return TextField(controller: _nameController);
  }
}
```

### InputDecoration

| Property | Description |
|----------|-------------|
| `labelText` | Floating label above the field |
| `hintText` | Placeholder text |
| `helperText` | Help message below |
| `errorText` | Error message (shows red) |
| `prefixIcon` | Icon at start |
| `suffixIcon` | Icon at end |
| `filled` | Background fill (bool) |
| `border` | Border style |

### Form Validation

```dart
Form(
  key: _formKey,
  child: Column(
    children: [
      TextFormField(
        decoration: const InputDecoration(labelText: 'Email'),
        validator: (value) {
          if (value == null || !value.contains('@')) {
            return 'Enter a valid email';
          }
          return null;
        },
      ),
      ElevatedButton(
        onPressed: () {
          if (_formKey.currentState!.validate()) {
            print('Form is valid');
          }
        },
        child: const Text('Submit'),
      ),
    ],
  ),
)
```

### Keyboard Types

```dart
TextField(
  keyboardType: TextInputType.emailAddress,
  textInputAction: TextInputAction.next,
  obscureText: true, // For passwords
  maxLines: 1,
  maxLength: 100,
)
```

| Keyboard Type | Use |
|---------------|-----|
| `TextInputType.text` | Default |
| `TextInputType.emailAddress` | Email |
| `TextInputType.phone` | Phone |
| `TextInputType.number` | Numeric |
| `TextInputType.multiline` | Multi-line |
| `TextInputType.url` | URL |

> **Key Point:** Always dispose of `TextEditingController` in `dispose()`. Use `Form` and `TextFormField` for validation. Use `obscureText: true` for passwords.

codeExample:
import 'package:flutter/material.dart';

class LoginForm extends StatefulWidget {
  const LoginForm({super.key});

  @override
  State<LoginForm> createState() => _LoginFormState();
}

class _LoginFormState extends State<LoginForm> {
  final _formKey = GlobalKey<FormState>();
  final _emailController = TextEditingController();
  final _passwordController = TextEditingController();

  @override
  void dispose() {
    _emailController.dispose();
    _passwordController.dispose();
    super.dispose();
  }

  void _submit() {
    if (_formKey.currentState!.validate()) {
      print('Email: ${_emailController.text}');
      print('Password: ${_passwordController.text}');
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Padding(
        padding: const EdgeInsets.all(16),
        child: Form(
          key: _formKey,
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              TextFormField(
                controller: _emailController,
                decoration: const InputDecoration(
                  labelText: 'Email',
                  prefixIcon: Icon(Icons.email),
                  border: OutlineInputBorder(),
                ),
                keyboardType: TextInputType.emailAddress,
                validator: (v) => (v == null || !v.contains('@')) ? 'Invalid email' : null,
              ),
              const SizedBox(height: 16),
              TextFormField(
                controller: _passwordController,
                decoration: const InputDecoration(
                  labelText: 'Password',
                  prefixIcon: Icon(Icons.lock),
                  border: OutlineInputBorder(),
                ),
                obscureText: true,
                validator: (v) => (v == null || v.length < 6) ? 'Min 6 characters' : null,
              ),
              const SizedBox(height: 24),
              ElevatedButton(
                onPressed: _submit,
                child: const Text('Login'),
              ),
            ],
          ),
        ),
      ),
    );
  }
}
